type CheckoutContext = {
  orderId: string;
  total: number;
};

type CheckoutEvent =
  | { type: 'ADD'; price: number }
  | { type: 'CONFIRM'; orderId: string };

type CheckoutOutput = {
  orderId: string;
  total: number;
