export const checkoutMachine = setup({
  types: {
    context: {} as CheckoutContext,
    events: {} as CheckoutEvent,
    output: {} as CheckoutOutput,
  },
}).createMachine({
  id: 'checkout',
  initial: 'cart',
  context: { orderId: '', total: 0 },
  states: {
    cart: {
      on: {
        ADD: {
          actions: assign({
            total: ({ context, event }) => context.total + event.price,
          }),
