In XState v5, a machine exposes a typed result via a top-level `output` function. The function runs when the machine finishes (either every root region is in a `final` state, or the root itself is marked `type: 'final'`), and the result is stored on `snapshot.output`. You declare the type in `setup({ types: { output } })` so consumers get full inference when they read `actor.getSnapshot().output`.

```ts
import { setup, assign } from 'xstate';

type Ctx = { items: string[] };
type Ev =
  | { type: 'ADD'; item: string }
  | { type: 'FINALIZE' };
type Out = { items: string[]; count: number };

export const listMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
    output: {} as Out,
  },
}).createMachine({
  id: 'list',
  initial: 'collecting',
  context: { items: [] },
  states: {
    collecting: {
      on: {
        ADD: {
          actions: assign({
            items: ({ context, event }) => [...context.items, event.item],
          }),
        },
        FINALIZE: 'done',
      },
    },
    done: { type: 'final' },
  },
  output: ({ context }) => ({
    items: context.items,
