// Persistence helpers — snapshot is the raw, structured-clone-safe value
// returned by getPersistedSnapshot(). Store it anywhere (localStorage,
// DB, ...). Invoked/spawned children are rehydrated along with the parent.
export function save(): Snapshot<unknown> {
  return stepperActor.getPersistedSnapshot();
}

export function load(snapshot: Snapshot<unknown>) {
  const restored = createActor(stepperMachine, { snapshot });
  restored.start();
  return restored;
}
