            target: ({ context }) => context.target + 1,
            adjustments: ({ context }) => context.adjustments + 1,
          }),
        },
        DEC: {
          actions: assign({
            target: ({ context }) => context.target - 1,
            adjustments: ({ context }) => context.adjustments + 1,
          }),
        },
      },
    },
  },
});
